#include <stdio.h>
#include <string.h>
#include <stdbool.h>

bool isPalindrome(const char *s, int l, int r) {
    while (l < r) {
        if (s[l] != s[r]) return false;
        l++; r--;
    }
    return true;
}

int minCuts(const char *s) {
    int n = strlen(s);
    // palindrome table
    bool pal[2000][2000] = {false};
    for (int center = 0; center < n; ++center) {
        // odd length
        int l = center, r = center;
        while (l >= 0 && r < n && s[l] == s[r]) {
            pal[l][r] = true;
            l--; r++;
        }
        // even length
        l = center; r = center + 1;
        while (l >= 0 && r < n && s[l] == s[r]) {
            pal[l][r] = true;
            l--; r++;
        }
    }
    int cut[2000];
    for (int i = 0; i < n; ++i) {
        if (pal[0][i]) {
            cut[i] = 0;
        } else {
            cut[i] = i; // worst case: cut each character
            for (int j = 0; j < i; ++j) {
                if (pal[j+1][i] && cut[j] + 1 < cut[i])
                    cut[i] = cut[j] + 1;
            }
        }
    }
    return cut[n-1];
}

int main() {
    int T; scanf("%d", &T);
    char s[2005];
    while (T--) {
        scanf("%s", s);
        printf("%d\n", minCuts(s));
    }
    return 0;
}

