#include <bits/stdc++.h>
using namespace std;

int minCuts(const string &s) {
    int n = s.size();
    vector<vector<bool>> pal(n, vector<bool>(n, false));
    for (int c = 0; c < n; ++c) {
        // odd length
        for (int l = c, r = c; l >= 0 && r < n && s[l] == s[r]; --l, ++r) pal[l][r] = true;
        // even length
        for (int l = c, r = c + 1; l >= 0 && r < n && s[l] == s[r]; --l, ++r) pal[l][r] = true;
    }
    vector<int> cut(n);
    for (int i = 0; i < n; ++i) {
        if (pal[0][i]) cut[i] = 0;
        else {
            cut[i] = i;
            for (int j = 0; j < i; ++j) if (pal[j+1][i] && cut[j] + 1 < cut[i]) cut[i] = cut[j] + 1;
        }
    }
    return cut[n-1];
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    int T; cin >> T;
    while (T--) {
        string s; cin >> s;
        cout << minCuts(s) << '\n';
    }
    return 0;
}

