            if (pal[0][i]) cut[i] = 0;
            else {
                cut[i] = i;
                for (int j = 0; j < i; ++j) {
                    if (pal[j+1][i] && cut[j] + 1 < cut[i]) cut[i] = cut[j] + 1;
