import sys

def min_cuts(s: str) -> int:
    n = len(s)
    pal = [[False] * n for _ in range(n)]
    for c in range(n):
        # odd length
        l = r = c
        while l >= 0 and r < n and s[l] == s[r]:
            pal[l][r] = True
            l -= 1
            r += 1
        # even length
        l, r = c, c + 1
        while l >= 0 and r < n and s[l] == s[r]:
            pal[l][r] = True
            l -= 1
            r += 1
    cut = [0] * n
    for i in range(n):
        if pal[0][i]:
            cut[i] = 0
        else:
            cut[i] = i
            for j in range(i):
                if pal[j+1][i] and cut[j] + 1 < cut[i]:
                    cut[i] = cut[j] + 1
    return cut[-1]

data = sys.stdin.read().splitlines()
T = int(data[0])
out = []
for i in range(1, T+1):
    out.append(str(min_cuts(data[i].strip())))
print('\n'.join(out))

